body.script:
'use strict';

// ─── JSON-RPC helper ───────────────────────────────────────
async function jsonRpc(url, params) {
    const resp = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'same-origin',
        body: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: params || {} }),
    });
    const data = await resp.json();
    if (data.error) {
        const msg = (data.error.data && data.error.data.message) || data.error.message || 'RPC Error';
        throw new Error(msg);
    }
    return data.result;
}

// ─── State ──────────────────────────────────────────────────
const state = {
    products: [], allProducts: [], categories: [],
    selectedCategoryId: 0,
    page: 1, perPage: 12, viewMode: 'grid',
    custResults: [],
    orderLines: [],
    employees: [], selectedEmployeeId: null, selectedEmployeeName: '',
    channel: 'walkin', tradeChannelOptions: [], defaultTradeChannel: '',
    defaultWarehouseId: null, locationId: null, locationName: '', sessionName: '',
    lastOrderData: null,
    returnOrderId: null, historyOrders: [],
    submitting: false, returnSubmitting: false,
    customerVisible: true,
    selectedPartnerId: null, creatingCustomer: false,
};

// ─── Helpers ────────────────────────────────────────────────
function fmt(n) {
    return '฿' + (Number(n) || 0).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}
function escapeHtml(s) {
    if (s === null || s === undefined) return '';
    return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
let toastTimer = null;
function showToast(msg, type) {
    const el = document.getElementById('posToast');
    el.textContent = msg;
    el.className = 'pos-toast ' + (type || 'success') + ' show';
    if (toastTimer) clearTimeout(toastTimer);
    toastTimer = setTimeout(function () { el.classList.remove('show'); }, type === 'error' ? 4200 : 2800);
}

// ─── Init ──────────────────────────────────────────────────
async function initPos() {
    if (!CURRENT_SESSION_ID) {
        document.getElementById('empScreen').classList.add('pos-hide');
        document.getElementById('noSessionScreen').classList.remove('pos-hide');
        return;
    }
    await loadSessionInfo();
    renderEmployees();
    // Single employee → auto-select, skip the picker
    if (state.employees.length === 1) {
        selectEmployee(state.employees[0].id, state.employees[0].name);
    }
}

async function loadSessionInfo() {
    try {
        const data = await jsonRpc('/pos_lite/api/session_info', { session_id: CURRENT_SESSION_ID });
        if (data.success) {
            state.employees = data.employees || [];
            state.defaultWarehouseId = data.default_warehouse_id;
            state.locationId = data.default_location_id || null;
            state.locationName = data.default_location_name || '';
            state.sessionName = data.session_name || ('#' + CURRENT_SESSION_ID);
            state.tradeChannelOptions = data.trade_channel_options || [];
            state.defaultTradeChannel = data.default_trade_channel || '';
            const si = document.getElementById('sessionInfo');
            if (si) si.textContent = 'Session: ' + state.sessionName + '  ·  พนักงาน ' + state.employees.length + ' คน';
            document.getElementById('posSessionName').textContent = state.sessionName;
            const locEl = document.getElementById('posLocationName');
            if (locEl) locEl.textContent = state.locationName || '—';
            renderTradeChannels();
        } else {
            showToast('โหลดข้อมูล session ไม่สำเร็จ: ' + (data.error || ''), 'error');
        }
    } catch (e) {
        console.error('Session info error', e);
        showToast('เชื่อมต่อเซิร์ฟเวอร์ไม่สำเร็จ', 'error');
    }
}

function renderTradeChannels() {
    const sel = document.getElementById('posTradeChannel');
    let html = '<option value="">Trade Channel (อัตโนมัติตามช่องทาง)</option>';
    state.tradeChannelOptions.forEach(function (o) {
        html += '<option value="' + escapeHtml(o.key) + '">' + escapeHtml(o.value) + '</option>';
    });
    sel.innerHTML = html;
    if (state.defaultTradeChannel) sel.value = state.defaultTradeChannel;
}

// ─── Employee Selection ────────────────────────────────────
function renderEmployees() {
    const grid = document.getElementById('empGrid');
    if (!state.employees.length) {
        grid.innerHTML = '<div style="color:rgba(255,255,255,0.75);grid-column:1/-1;line-height:1.7;">'
            + 'ไม่พบพนักงานใน session นี้<br/>กรุณาเพิ่มพนักงานในหน้า Session ก่อน</div>';
        return;
    }
    let html = '';
    state.employees.forEach(function (emp, idx) {
        const initial = (emp.name || '?').charAt(0).toUpperCase();
        html += '<div class="emp-card" data-emp-idx="' + idx + '">'
            + '<div class="emp-avatar">' + escapeHtml(initial) + '</div>'
            + '<div class="emp-name">' + escapeHtml(emp.name) + '</div>'
            + '<div class="emp-sub">พนักงานขาย</div></div>';
    });
    grid.innerHTML = html;
    grid.querySelectorAll('.emp-card').forEach(function (card) {
        card.addEventListener('click', function () {
            const emp = state.employees[parseInt(this.getAttribute('data-emp-idx'))];
            if (emp) selectEmployee(emp.id, emp.name);
        });
    });
}

function selectEmployee(empId, empName) {
    state.selectedEmployeeId = empId;
    state.selectedEmployeeName = empName;
    document.getElementById('empScreen').classList.add('pos-hide');
    document.getElementById('posTerminal').classList.remove('pos-hide');
    document.getElementById('posEmployeeName').textContent = '👤 ' + empName;
    startTerminal();
}

function showEmployeeSwitch() {
    const list = document.getElementById('empSwitchList');
    let html = '';
    state.employees.forEach(function (emp, idx) {
        const isActive = emp.id === state.selectedEmployeeId;
        html += '<div class="pos-history-order" data-switch-idx="' + idx + '"'
            + (isActive ? ' style="border-color:var(--primary);background:var(--primary-bg);"' : '') + '>'
            + '<div class="ho-info"><div class="ho-name">' + escapeHtml(emp.name) + '</div>'
            + '<div class="ho-meta">' + (isActive ? '✓ กำลังใช้งาน' : 'แตะเพื่อเลือก') + '</div></div></div>';
    });
    list.innerHTML = html || '<p style="font-size:13px;color:var(--text-secondary);">ไม่มีพนักงาน</p>';
    list.querySelectorAll('[data-switch-idx]').forEach(function (card) {
        card.addEventListener('click', function () {
            const emp = state.employees[parseInt(this.getAttribute('data-switch-idx'))];
            if (emp) {
                state.selectedEmployeeId = emp.id;
                state.selectedEmployeeName = emp.name;
                document.getElementById('posEmployeeName').textContent = '👤 ' + emp.name;
                showToast('เปลี่ยนพนักงานเป็น ' + emp.name, 'success');
                closeEmployeeSwitch();
            }
        });
    });
    document.getElementById('posEmpSwitchModal').classList.add('open');
}
function closeEmployeeSwitch() { document.getElementById('posEmpSwitchModal').classList.remove('open'); }

// ─── Channel ───────────────────────────────────────────────
function selectChannel(channel) {
    state.channel = channel;
    document.querySelectorAll('#posChannelRow .pos-channel-btn').forEach(function (b) {
        b.classList.toggle('active', b.getAttribute('data-channel') === channel);
    });
}

function toggleCustomer() {
    state.customerVisible = !state.customerVisible;
    document.getElementById('custFields').style.display = state.customerVisible ? '' : 'none';
    document.getElementById('custToggle').textContent = state.customerVisible ? 'ซ่อน' : 'แสดง';
}

// ─── New Customer ──────────────────────────────────────────
function openNewCustomer() {
    document.getElementById('ncName').value = document.getElementById('custName').value.trim();
    document.getElementById('ncPhone').value = document.getElementById('custPhone').value.trim();
    document.getElementById('ncVat').value = '';
    document.getElementById('ncBranch').value = '00000';
    document.getElementById('ncStreet').value = '';
    document.getElementById('ncCity').value = '';
    document.getElementById('ncZip').value = '';
    document.getElementById('posNewCustomerModal').classList.add('open');
    document.getElementById('ncName').focus();
}
function closeNewCustomer() {
    if (state.creatingCustomer) return;
    document.getElementById('posNewCustomerModal').classList.remove('open');
}
function setSelectedPartner(partner) {
    state.selectedPartnerId = partner ? partner.id : null;
    const badge = document.getElementById('custPartnerBadge');
    if (partner) {
        document.getElementById('custPartnerBadgeName').textContent = '✓ ' + partner.name;
        badge.style.display = '';
    } else {
        badge.style.display = 'none';
    }
}
function clearSelectedPartner(clearFields) {
    if (!state.selectedPartnerId) return;
    setSelectedPartner(null);
    if (clearFields === true) {
        document.getElementById('custName').value = '';
        document.getElementById('custPhone').value = '';
        document.getElementById('custAddress').value = '';
    }
}
// ─── Customer Search ───────────────────────────────────────
let custSearchTimer = null;
function onCustSearchInput() {
    if (custSearchTimer) clearTimeout(custSearchTimer);
    custSearchTimer = setTimeout(doCustSearch, 250);
}

async function doCustSearch() {
    const term = document.getElementById('custSearch').value.trim();
    if (term.length < 2) { closeCustResults(); return; }
    try {
        const data = await jsonRpc('/pos_lite/api/customer_search', { term: term });
        if (!data.success) return;
        state.custResults = data.customers || [];
        const box = document.getElementById('custResults');
        if (!state.custResults.length) {
            box.innerHTML = '<div class="pos-cust-empty">ไม่พบลูกค้า "' + escapeHtml(term) + '"</div>';
        } else {
            let html = '';
            state.custResults.forEach(function (c, idx) {
                html += '<div class="pos-cust-result" data-cust-idx="' + idx + '">'
                    + '<div class="cr-name">' + escapeHtml(c.name) + '</div>'
                    + '<div class="cr-sub">' + escapeHtml([c.phone, c.vat].filter(Boolean).join(' · ') || '—') + '</div></div>';
            });
            box.innerHTML = html;
            box.querySelectorAll('[data-cust-idx]').forEach(function (row) {
                row.addEventListener('click', function () {
                    pickCustomer(state.custResults[parseInt(this.getAttribute('data-cust-idx'))]);
                });
            });
        }
        box.classList.add('open');
    } catch (e) { /* silent — autocomplete only */ }
}

function pickCustomer(c) {
    if (!c) return;
    document.getElementById('custName').value = c.name;
    document.getElementById('custPhone').value = c.phone || '';
    document.getElementById('custAddress').value = c.address || '';
    setSelectedPartner(c);
    document.getElementById('custSearch').value = '';
    closeCustResults();
    showToast('เลือกลูกค้า ' + c.name, 'success');
}

function closeCustResults() {
    document.getElementById('custResults').classList.remove('open');
}

async function saveNewCustomer() {
    if (state.creatingCustomer) return;
    const name = document.getElementById('ncName').value.trim();
    if (!name) { showToast('กรุณากรอกชื่อลูกค้า', 'error'); return; }
    const vat = document.getElementById('ncVat').value.trim();
    if (vat && !/^\d{13}$/.test(vat)) { showToast('เลขประจำตัวผู้เสียภาษีต้องเป็นตัวเลข 13 หลัก', 'error'); return; }

    state.creatingCustomer = true;
    const btn = document.getElementById('ncSaveBtn');
    btn.disabled = true;
    // Static markup only — no user data goes through innerHTML here.
    btn.innerHTML = '<span class="pos-spinner"></span>กำลังบันทึก...';
    try {
        const data = await jsonRpc('/pos_lite/api/create_customer', {
            name: name,
            vat: vat,
            branch: document.getElementById('ncBranch').value.trim(),
            phone: document.getElementById('ncPhone').value.trim(),
            street: document.getElementById('ncStreet').value.trim(),
            city: document.getElementById('ncCity').value.trim(),
            zip: document.getElementById('ncZip').value.trim(),
        });
        if (data.success) {
            const p = data.partner;
            document.getElementById('custName').value = p.name;
            document.getElementById('custPhone').value = p.phone;
            document.getElementById('custAddress').value = p.address;
            setSelectedPartner(p);
            state.creatingCustomer = false;
            closeNewCustomer();
            showToast('สร้างลูกค้า ' + p.name + ' สำเร็จ', 'success');
        } else {
            showToast('เกิดข้อผิดพลาด: ' + (data.error || 'ไม่ทราบสาเหตุ'), 'error');
        }
    } catch (e) {
        showToast('ไม่สามารถสร้างลูกค้าได้: ' + e.message, 'error');
    } finally {
        state.creatingCustomer = false;
        btn.disabled = false;
        btn.textContent = 'บันทึกลูกค้า';
    }
}

// ─── Terminal Start ────────────────────────────────────────
async function startTerminal() {
    // Location is locked to the session's config (per-location POS). The server
    // resolves the stock location from the session, so we just load products.
    await loadProducts();
}

function reloadProducts() {
    loadProducts();
    showToast('โหลดสินค้าใหม่แล้ว', 'success');
}

async function loadProducts() {
    try {
        const data = await jsonRpc('/pos_lite/api/products', {
            session_id: CURRENT_SESSION_ID,
        });
        if (data.success) {
            state.allProducts = data.products || [];
            buildCategories();
            filterProducts();
        } else {
            showToast('โหลดสินค้าไม่สำเร็จ: ' + (data.error || ''), 'error');
        }
    } catch (e) { showToast('โหลดสินค้าไม่สำเร็จ', 'error'); }
}

const INLINE_CATS = 4; // chips shown inline; the rest go into the "เพิ่มเติม" menu

function buildCategories() {
    const seen = {};
    const cats = [];
    state.allProducts.forEach(function (p) {
        if (Array.isArray(p.categ_id) && p.categ_id.length === 2 && !seen[p.categ_id[0]]) {
            seen[p.categ_id[0]] = true;
            cats.push({ id: p.categ_id[0], name: p.categ_id[1] });
        }
    });
    cats.sort(function (a, b) { return a.name.localeCompare(b.name); });
    state.categories = cats;
    if (cats.length && !cats.some(function (c) { return c.id === state.selectedCategoryId; })) {
        state.selectedCategoryId = 0;
    }
    renderCategories();
}

function renderCategories() {
    const row = document.getElementById('posCatsRow');
    const el = document.getElementById('posCats');
    const moreBtn = document.getElementById('posCatMoreBtn');
    const menu = document.getElementById('posCatMenu');
    const cats = state.categories;
    if (cats.length < 2) {
        row.style.display = 'none';
        el.innerHTML = ''; menu.innerHTML = '';
        state.selectedCategoryId = 0;
        return;
    }
    row.style.display = '';
    const inline = cats.slice(0, INLINE_CATS);
    const overflow = cats.slice(INLINE_CATS);

    let html = '<button type="button" class="pos-cat-chip' + (state.selectedCategoryId === 0 ? ' active' : '') + '" data-cat="0">ทั้งหมด</button>';
    inline.forEach(function (c) {
        html += '<button type="button" class="pos-cat-chip' + (state.selectedCategoryId === c.id ? ' active' : '') + '" data-cat="' + c.id + '">' + escapeHtml(c.name) + '</button>';
    });
    el.innerHTML = html;
    el.querySelectorAll('.pos-cat-chip').forEach(function (chip) {
        chip.addEventListener('click', function () {
            selectCategory(parseInt(this.getAttribute('data-cat')) || 0);
        });
    });

    if (!overflow.length) {
        moreBtn.style.display = 'none';
        menu.innerHTML = '';
        return;
    }
    moreBtn.style.display = '';
    const overflowActive = overflow.some(function (c) { return c.id === state.selectedCategoryId; });
    moreBtn.classList.toggle('active', overflowActive);
    let mhtml = '';
    overflow.forEach(function (c) {
        mhtml += '<button type="button" class="' + (state.selectedCategoryId === c.id ? 'active' : '') + '" data-cat="' + c.id + '">' + escapeHtml(c.name) + '</button>';
    });
    menu.innerHTML = mhtml;
    menu.querySelectorAll('button').forEach(function (btn) {
        btn.addEventListener('click', function () {
            selectCategory(parseInt(this.getAttribute('data-cat')) || 0);
        });
    });
}

function selectCategory(catId) {
    state.selectedCategoryId = catId;
    closeCatMenu();
    renderCategories();
    filterProducts();
}

function toggleCatMenu(ev) {
    if (ev) ev.stopPropagation();
    document.getElementById('posCatMenu').classList.toggle('open');
}
function closeCatMenu() { document.getElementById('posCatMenu').classList.remove('open'); }

function filterProducts() {
    const term = document.getElementById('posSearch').value.toLowerCase().trim();
    let filtered = state.allProducts;
    if (state.selectedCategoryId) {
        filtered = filtered.filter(function (p) { return Array.isArray(p.categ_id) && p.categ_id[0] === state.selectedCategoryId; });
    }
    if (term) {
        filtered = filtered.filter(function (p) {
            return (p.name && p.name.toLowerCase().includes(term))
                || (p.default_code && p.default_code.toLowerCase().includes(term))
                || (p.barcode && String(p.barcode).toLowerCase().includes(term));
        });
    }
    state.products = filtered;
    state.page = 1;
    renderProducts();
}

// Barcode-scanner friendly: Enter adds an exact barcode/code match, or the only result
function onSearchKey(ev) {
    if (ev.key !== 'Enter') return;
    ev.preventDefault();
    const term = document.getElementById('posSearch').value.toLowerCase().trim();
    if (!term) return;
    let match = state.allProducts.find(function (p) {
        return (p.barcode && String(p.barcode).toLowerCase() === term)
            || (p.default_code && p.default_code.toLowerCase() === term);
    });
    if (!match && state.products.length === 1) match = state.products[0];
    if (match) {
        addProduct(match.id);
        document.getElementById('posSearch').value = '';
        filterProducts();
    } else {
        showToast('ไม่พบสินค้า: ' + term, 'warning');
    }
}

function stockBadgeHtml(p, isStatic) {
    const qty = typeof p.qty_available === 'number' ? p.qty_available : 0;
    const isService = p.type === 'service';
    const cls = 'pos-stock-badge' + (isStatic ? ' static' : '');
    if (isService) return '<span class="' + cls + ' in-stock">บริการ</span>';
    if (qty <= 0) return '<span class="' + cls + ' no-stock">หมด</span>';
    if (qty < 5) return '<span class="' + cls + ' low-stock">เหลือ ' + qty + '</span>';
    return '<span class="' + cls + ' in-stock">' + qty + '</span>';
}

function renderProducts() {
    const el = document.getElementById('posProducts');
    const totalPages = Math.max(1, Math.ceil(state.products.length / state.perPage));
    if (state.page > totalPages) state.page = totalPages;
    if (state.page < 1) state.page = 1;

    if (!state.products.length) {
        el.classList.remove('list-view');
        el.innerHTML = '<div class="pos-no-products"><svg width="38" height="38" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/></svg>ไม่พบสินค้า</div>';
        renderPagination(0);
        return;
    }

    const cartQty = {};
    state.orderLines.forEach(function (l) { cartQty[l.productId] = l.qty; });
    const start = (state.page - 1) * state.perPage;
    const pageItems = state.products.slice(start, start + state.perPage);
    const listMode = state.viewMode === 'list';
    el.classList.toggle('list-view', listMode);

    let html = '';
    pageItems.forEach(function (p) {
        const qty = typeof p.qty_available === 'number' ? p.qty_available : 0;
        const isService = p.type === 'service';
        const outOfStock = !isService && qty <= 0;
        const inCart = cartQty[p.id] || 0;
        if (listMode) {
            const imgHtml = p.image_128
                ? '<img class="pr-img" loading="lazy" src="data:image/png;base64,' + p.image_128 + '" alt=""/>'
                : '<div class="pr-img-placeholder">📦</div>';
            html += '<div class="pos-product-row' + (outOfStock ? ' out-of-stock' : '') + '"'
                + (outOfStock ? '' : ' data-prod-id="' + p.id + '"') + '>'
                + imgHtml
                + '<div class="pr-info"><div class="pr-name">' + escapeHtml(p.name) + '</div>'
                + (p.default_code ? '<div class="pr-code">' + escapeHtml(p.default_code) + '</div>' : '')
                + '</div>'
                + (inCart ? '<span class="pos-cart-count-badge" style="position:static;">' + inCart + '</span>' : '')
                + stockBadgeHtml(p, true)
                + '<span class="pr-price">' + fmt(p.list_price) + '</span></div>';
        } else {
            const imageHtml = p.image_256
                ? '<img class="pos-product-img" loading="lazy" src="data:image/png;base64,' + p.image_256 + '" alt=""/>'
                : '<div class="pos-product-img-placeholder">📦</div>';
            const cartBadge = inCart ? '<span class="pos-cart-count-badge">' + inCart + '</span>' : '';
            html += '<div class="pos-product-card' + (outOfStock ? ' out-of-stock' : '') + '"'
                + (outOfStock ? '' : ' data-prod-id="' + p.id + '"') + '>'
                + imageHtml + stockBadgeHtml(p, false) + cartBadge
                + '<div class="pos-product-info"><div class="pos-product-name">' + escapeHtml(p.name) + '</div>'
                + (p.default_code ? '<div class="pos-product-code">' + escapeHtml(p.default_code) + '</div>' : '')
                + '<div class="pos-product-price">' + fmt(p.list_price) + '</div></div></div>';
        }
    });
    el.innerHTML = html;
    el.querySelectorAll('[data-prod-id]').forEach(function (card) {
        card.addEventListener('click', function () {
            addProduct(parseInt(this.getAttribute('data-prod-id')));
        });
    });
    renderPagination(totalPages);
}

// ─── Pagination ────────────────────────────────────────────
function pageWindow(current, total) {
    // Mirrors the mockup: 1 2 3 4 5 … 12 with a sliding window around the
    // current page. Returns page numbers with 0 as the ellipsis marker.
    if (total <= 7) {
        const all = [];
        for (let i = 1; i <= total; i++) all.push(i);
        return all;
    }
    if (current <= 4) return [1, 2, 3, 4, 5, 0, total];
    if (current >= total - 3) return [1, 0, total - 4, total - 3, total - 2, total - 1, total];
    return [1, 0, current - 1, current, current + 1, 0, total];
}

function renderPagination(totalPages) {
    const bar = document.getElementById('posPagination');
    if (!totalPages) { bar.style.display = 'none'; return; }
    bar.style.display = 'flex';
    document.getElementById('pgPrev').disabled = state.page <= 1;
    document.getElementById('pgNext').disabled = state.page >= totalPages;
    const numbers = document.getElementById('pgNumbers');
    let html = '';
    pageWindow(state.page, totalPages).forEach(function (n) {
        if (n === 0) { html += '<span class="pos-page-ellipsis">…</span>'; return; }
        html += '<button type="button" class="pos-page-btn' + (n === state.page ? ' active' : '') + '" data-page="' + n + '">' + n + '</button>';
    });
    numbers.innerHTML = html;
    numbers.querySelectorAll('[data-page]').forEach(function (btn) {
        btn.addEventListener('click', function () {
            gotoPage(parseInt(this.getAttribute('data-page')));
        });
    });
}

function gotoPage(n) {
    const totalPages = Math.max(1, Math.ceil(state.products.length / state.perPage));
    n = Math.min(Math.max(1, n), totalPages);
    if (n === state.page) return;
    state.page = n;
    renderProducts();
    document.getElementById('posProducts').scrollTop = 0;
}

function setPerPage(v) {
    state.perPage = parseInt(v) || 12;
    state.page = 1;
    renderProducts();
}

function setViewMode(mode) {
    state.viewMode = mode === 'list' ? 'list' : 'grid';
    document.getElementById('viewGridBtn').classList.toggle('active', state.viewMode === 'grid');
    document.getElementById('viewListBtn').classList.toggle('active', state.viewMode === 'list');
    renderProducts();
}

// ─── Cart ──────────────────────────────────────────────────
function addProduct(id) {
    const prod = state.allProducts.find(function (p) { return p.id === id; });
    if (!prod) return;
    const qtyAvailable = typeof prod.qty_available === 'number' ? prod.qty_available : 0;
    const isService = prod.type === 'service';
    const existing = state.orderLines.find(function (l) { return l.productId === id; });
    const currentQty = existing ? existing.qty : 0;
    if (!isService && currentQty + 1 > qtyAvailable) { showToast('สต๊อกไม่พอ: ' + prod.name + ' (เหลือ ' + qtyAvailable + ')', 'error'); return; }
    if (existing) { existing.qty += 1; }
    else {
        state.orderLines.push({
            productId: id, name: prod.name, price: prod.list_price,
            code: prod.default_code || '', qty: 1, discount: 0,
            image: prod.image_128 || null,
            tax_rate: typeof prod.tax_rate === 'number' ? prod.tax_rate : 0,
            maxQty: isService ? null : qtyAvailable,
        });
    }
    renderOrder(); updateTotals(); renderProducts();
}

function changeQty(id, delta) {
    const line = state.orderLines.find(function (l) { return l.productId === id; });
    if (!line) return;
    setQty(id, line.qty + delta);
}

function setQty(id, newQty) {
    const line = state.orderLines.find(function (l) { return l.productId === id; });
    if (!line) return;
    newQty = Math.floor(Number(newQty) || 0);
    if (newQty <= 0) {
        state.orderLines = state.orderLines.filter(function (l) { return l.productId !== id; });
    } else {
        const prod = state.allProducts.find(function (p) { return p.id === id; });
        const maxQty = prod && typeof prod.qty_available === 'number' ? prod.qty_available : line.maxQty;
        if (prod && prod.type !== 'service' && newQty > maxQty) {
            showToast('สต๊อกไม่พอ: ' + line.name + ' (เหลือ ' + maxQty + ')', 'error');
            newQty = Math.max(Math.floor(maxQty), 1);
        }
        line.qty = newQty;
    }
    renderOrder(); updateTotals(); renderProducts();
}

function removeLine(id) {
    state.orderLines = state.orderLines.filter(function (l) { return l.productId !== id; });
    renderOrder(); updateTotals(); renderProducts();
}

function setDiscount(id, val) {
    const line = state.orderLines.find(function (l) { return l.productId === id; });
    if (!line) return;
    let disc = Math.max(parseFloat(val) || 0, 0);
    if (disc > line.price) {
        showToast('ส่วนลดเกินราคาสินค้า', 'warning');
        disc = line.price;
    }
    line.discount = disc;
    renderOrder(); updateTotals();
}

function clearCart() {
    if (!state.orderLines.length) return;
    state.orderLines = [];
    renderOrder(); updateTotals(); renderProducts();
}

function cancelBill() {
    if (!state.orderLines.length) return;
    if (!window.confirm('ยกเลิกบิลนี้ทั้งหมด?')) return;
    state.orderLines = [];
    document.getElementById('custName').value = '';
    document.getElementById('custPhone').value = '';
    document.getElementById('custAddress').value = '';
    document.getElementById('custSearch').value = '';
    setSelectedPartner(null);
    closeCustResults();
    renderOrder(); updateTotals(); renderProducts();
    showToast('ยกเลิกบิลแล้ว', 'warning');
}

function lineTotal(l) {
    return Math.max(l.price - (l.discount || 0), 0) * l.qty;
}

function renderOrder() {
    const el = document.getElementById('posOrderLines');
    document.getElementById('cartCount').textContent = state.orderLines.reduce(function (s, l) { return s + l.qty; }, 0);
    if (!state.orderLines.length) {
        el.innerHTML = '<div class="pos-empty-cart"><svg width="30" height="30" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/></svg>แตะสินค้าด้านซ้ายเพื่อเพิ่มรายการ</div>';
        return;
    }
    let html = '';
    state.orderLines.forEach(function (l) {
        const imgHtml = l.image
            ? '<img class="pos-order-line-img" src="data:image/png;base64,' + l.image + '"/>'
            : '<div class="pos-order-line-img-placeholder">📦</div>';
        html += '<div class="pos-order-line">' + imgHtml
            + '<div class="pos-order-line-info">'
            + '<div class="pos-order-line-name" title="' + escapeHtml(l.name) + '">' + escapeHtml(l.name) + '</div>'
            + '<div class="pos-order-line-unit">' + fmt(l.price) + ' / หน่วย' + (l.discount ? ' · ลด ' + fmt(l.discount) : '') + '</div>'
            + '<div class="pos-order-line-controls">'
            + '<button type="button" class="pos-qty-btn" onclick="changeQty(' + l.productId + ', -1)">−</button>'
            + '<input type="number" class="pos-qty-input" min="0" step="1" value="' + l.qty + '" onchange="setQty(' + l.productId + ', this.value)"/>'
            + '<button type="button" class="pos-qty-btn" onclick="changeQty(' + l.productId + ', 1)">+</button>'
            + '<div class="pos-line-disc"><input type="number" min="0" step="0.01" placeholder="ส่วนลด" value="' + (l.discount || '') + '" onchange="setDiscount(' + l.productId + ', this.value)"/><span>฿</span></div>'
            + '</div></div>'
            + '<div class="pos-order-line-right">'
            + '<div class="pos-order-line-price">' + fmt(lineTotal(l)) + '</div>'
            + '<button type="button" class="pos-order-line-remove" onclick="removeLine(' + l.productId + ')" title="ลบรายการ">'
            + '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>'
            + '</button></div></div>';
    });
    el.innerHTML = html;
}

function computeTotals() {
    let subtotal = 0, tax = 0;
    state.orderLines.forEach(function (l) {
        const base = lineTotal(l);
        subtotal += base;
        tax += base * (l.tax_rate || 0) / 100;
    });
    subtotal = Math.round(subtotal * 100) / 100;
    tax = Math.round(tax * 100) / 100;
    return { subtotal: subtotal, tax: tax, total: Math.round((subtotal + tax) * 100) / 100 };
}

function updateTotals() {
    const t = computeTotals();
    document.getElementById('posSubtotal').textContent = fmt(t.subtotal);
    document.getElementById('posTax').textContent = fmt(t.tax);
    document.getElementById('posTotal').textContent = fmt(t.total);
    const btn = document.getElementById('posPayBtn');
    const txt = document.getElementById('posPayBtnText');
    const cancelBtn = document.getElementById('posCancelBillBtn');
    if (state.orderLines.length) {
        btn.disabled = false;
        cancelBtn.disabled = false;
        txt.textContent = 'ชำระเงิน ' + fmt(t.total);
    } else {
        btn.disabled = true;
        cancelBtn.disabled = true;
        txt.textContent = 'ชำระเงิน';
    }
}

// ─── Checkout ──────────────────────────────────────────────
function openProcessModal() {
    if (!state.orderLines.length) return;
    const t = computeTotals();
    document.getElementById('modalTotal').textContent = fmt(t.total);
    let html = '';
    state.orderLines.forEach(function (l) {
        html += '<div class="pos-checkout-line"><span class="cl-name">' + escapeHtml(l.name) + ' × ' + l.qty + '</span>'
            + '<span class="cl-amt">' + fmt(lineTotal(l)) + '</span></div>';
    });
    const custName = document.getElementById('custName').value.trim();
    html += '<div class="pos-checkout-line" style="border-top:1px solid var(--border);margin-top:4px;padding-top:7px;">'
        + '<span class="cl-name" style="color:var(--text-secondary);">👤 ' + escapeHtml(custName || 'Walk-in Customer')
        + ' · ' + escapeHtml(state.selectedEmployeeName) + '</span></div>';
    document.getElementById('checkoutLines').innerHTML = html;
    document.getElementById('posProcessModal').classList.add('open');
}
function closeProcessModal() {
    if (state.submitting) return;
    document.getElementById('posProcessModal').classList.remove('open');
}

async function confirmProcess() {
    if (state.submitting || !state.orderLines.length) return;
    state.submitting = true;
    const btn = document.getElementById('confirmProcessBtn');
    btn.disabled = true;
    btn.innerHTML = '<span class="pos-spinner"></span>กำลังบันทึก...';

    const params = {
        partner_id: state.selectedPartnerId,
        customer_name: document.getElementById('custName').value.trim(),
        partner_phone: document.getElementById('custPhone').value.trim(),
        partner_address: document.getElementById('custAddress').value.trim(),
        channel: state.channel,
        trade_channel: document.getElementById('posTradeChannel').value || null,
        note: document.getElementById('orderNote').value.trim(),
        session_id: CURRENT_SESSION_ID,
        employee_id: state.selectedEmployeeId,
        line_ids: state.orderLines.map(function (l) {
            return {
                product_id: l.productId, qty: l.qty, price_unit: l.price,
                discount: l.discount || 0, discount_type: 'fixed',
            };
        }),
    };

    try {
        const data = await jsonRpc('/pos_lite/api/create_order', params);
        if (data.success) {
            state.orderLines = [];
            renderOrder(); updateTotals();
            document.getElementById('orderNote').value = '';
            document.getElementById('custName').value = '';
            document.getElementById('custPhone').value = '';
            document.getElementById('custAddress').value = '';
            setSelectedPartner(null);
            closeProcessModalForce();
            showToast('บันทึกออเดอร์ ' + data.name + ' สำเร็จ', 'success');
            await loadAndShowPrintDetail(data.order_id, data.name);
            loadProducts(); // refresh stock badges
        } else {
            showToast('เกิดข้อผิดพลาด: ' + (data.error || 'ไม่ทราบสาเหตุ'), 'error');
        }
    } catch (e) {
        showToast('ไม่สามารถสร้างออเดอร์ได้: ' + e.message, 'error');
    } finally {
        state.submitting = false;
        btn.disabled = false;
        btn.innerHTML = 'ยืนยันการขาย';
    }
}
function closeProcessModalForce() { document.getElementById('posProcessModal').classList.remove('open'); }

// ─── Success / Print ───────────────────────────────────────
async function loadAndShowPrintDetail(orderId, orderName) {
    try {
        const data = await jsonRpc('/pos_lite/api/order_detail', { order_id: orderId });
        if (data.success) {
            state.lastOrderData = data.order;
            renderPrintDetail();
        } else {
            showSimplePrintDetail(orderName);
        }
    } catch (e) {
        showSimplePrintDetail(orderName);
    }
    document.getElementById('posPrintDetailModal').classList.add('open');
}

function renderPrintDetail() {
    const o = state.lastOrderData;
    if (!o) return;
    document.getElementById('printOrderName').textContent = o.name;
    document.getElementById('printOrderDate').textContent = o.date_order ? new Date(o.date_order + 'Z').toLocaleString('th-TH') : '';
    let html = '<div class="pos-print-summary-row label"><span>รายการ</span><span>รวม</span></div>';
    (o.lines || []).forEach(function (l) {
        html += '<div class="pos-print-summary-row"><span>' + escapeHtml(l.product_name) + ' × ' + l.qty + '</span><span>' + fmt(l.price_total) + '</span></div>';
    });
    html += '<div class="pos-print-summary-row total"><span>รวมสุทธิ</span><span>' + fmt(o.amount_total) + '</span></div>';
    document.getElementById('printOrderSummary').innerHTML = html;
    const invBtn = document.getElementById('printInvoiceBtn');
    invBtn.style.display = (o.print_urls && o.print_urls.invoice) ? '' : 'none';
}

function showSimplePrintDetail(orderName) {
    state.lastOrderData = { name: orderName, print_urls: null };
    document.getElementById('printOrderName').textContent = orderName;
    document.getElementById('printOrderDate').textContent = '';
    document.getElementById('printOrderSummary').innerHTML = '';
    document.getElementById('printInvoiceBtn').style.display = 'none';
}

function printReceipt(size) {
    const o = state.lastOrderData;
    if (!o || !o.print_urls) { showToast('ไม่พบลิงก์เอกสาร', 'warning'); return; }
    const url = o.print_urls['receipt_' + size];
    if (url) window.open(url, '_blank');
}

function printInvoice() {
    const o = state.lastOrderData;
    if (o && o.print_urls && o.print_urls.invoice) window.open(o.print_urls.invoice, '_blank');
}

function closePrintDetail() {
    document.getElementById('posPrintDetailModal').classList.remove('open');
    document.getElementById('posSearch').focus();
}

// ─── History / Return ──────────────────────────────────────
async function showHistoryOrders() {
    document.getElementById('posHistoryModal').classList.add('open');
    document.getElementById('historySearch').value = '';
    document.getElementById('historyOrderList').innerHTML = '<p style="color:var(--text-secondary);font-size:13px;">กำลังโหลด...</p>';
    try {
        const data = await jsonRpc('/pos_lite/api/orders_for_return', { limit: 80 });
        if (data.success) {
            state.historyOrders = data.orders || [];
            renderHistoryList(state.historyOrders);
        }
    } catch (e) { showToast('โหลดประวัติไม่สำเร็จ', 'error'); }
}

function filterHistory() {
    const term = document.getElementById('historySearch').value.toLowerCase().trim();
    const filtered = term
        ? state.historyOrders.filter(function (o) {
            return (o.name && o.name.toLowerCase().includes(term))
                || (o.customer_name && o.customer_name.toLowerCase().includes(term));
        })
        : state.historyOrders;
    renderHistoryList(filtered);
}

function renderHistoryList(orders) {
    const list = document.getElementById('historyOrderList');
    if (!orders.length) {
        list.innerHTML = '<p style="color:var(--text-secondary);font-size:13px;text-align:center;padding:24px 0;">ไม่มีออเดอร์</p>';
        return;
    }
    let html = '';
    orders.forEach(function (o, idx) {
        const dateStr = o.date_order ? new Date(o.date_order + 'Z').toLocaleString('th-TH', { dateStyle: 'short', timeStyle: 'short' }) : '';
        html += '<div class="pos-history-order" data-order-id="' + o.id + '" data-order-name="' + escapeHtml(o.name) + '">'
            + '<div class="ho-info"><div class="ho-name">' + escapeHtml(o.name) + '</div>'
            + '<div class="ho-meta">' + dateStr + ' · ' + escapeHtml(o.customer_name || 'ลูกค้า')
            + (o.employee_name ? ' · ' + escapeHtml(o.employee_name) : '') + '</div></div>'
            + '<div class="ho-amount">' + fmt(o.amount_total) + '</div></div>';
    });
    list.innerHTML = html;
    list.querySelectorAll('.pos-history-order').forEach(function (el) {
        el.addEventListener('click', function () {
            openReturnWizard(parseInt(this.getAttribute('data-order-id')), this.getAttribute('data-order-name'));
        });
    });
}

function closeHistoryOrders() { document.getElementById('posHistoryModal').classList.remove('open'); }

// ─── Return Wizard (partial qty supported) ─────────────────
async function openReturnWizard(orderId, orderName) {
    closeHistoryOrders();
    state.returnOrderId = orderId;
    document.getElementById('returnWizardTitle').textContent = '🔄 คืนสินค้า — ' + orderName;
    document.getElementById('returnWizardBody').innerHTML = '<p style="color:var(--text-secondary);font-size:13px;">กำลังโหลด...</p>';
    document.getElementById('posReturnWizardModal').classList.add('open');

    try {
        const data = await jsonRpc('/pos_lite/api/order_detail', { order_id: orderId });
        if (!data.success) { showToast('โหลดรายละเอียดออเดอร์ไม่สำเร็จ', 'error'); return; }
        const o = data.order;
        let html = '<div style="margin-bottom:12px;"><div class="pos-section-title">เลือกสินค้าและจำนวนที่ต้องการคืน</div>';
        (o.lines || []).forEach(function (l, idx) {
            const avail = typeof l.available_return_qty === 'number' ? l.available_return_qty : l.qty;
            const disabled = avail <= 0;
            html += '<div class="pos-return-line' + (disabled ? ' disabled' : '') + '">'
                + '<input type="checkbox" class="return-checkbox" id="retCb' + idx + '"'
                + ' data-product-id="' + l.product_id + '" data-price="' + l.price_unit + '" data-max="' + avail + '"'
                + (disabled ? ' disabled="disabled"' : '') + ' onchange="onReturnCheckChange(' + idx + ')"/>'
                + '<label class="rl-info" for="retCb' + idx + '">'
                + '<div class="rl-name">' + escapeHtml(l.product_name) + '</div>'
                + '<div class="rl-sub">ซื้อ ' + l.qty + (l.returned_qty ? ' · คืนแล้ว ' + l.returned_qty : '') + ' · คืนได้ ' + avail + '</div></label>'
                + '<div class="rl-qty-wrap">'
                + '<input type="number" class="pos-qty-input return-qty" id="retQty' + idx + '" min="1" max="' + avail + '" step="1" value="' + Math.max(avail, 1) + '"'
                + (disabled ? ' disabled="disabled"' : '') + ' style="width:52px;" onchange="clampReturnQty(' + idx + ')" oninput="calcReturnTotal()"/>'
                + '</div>'
                + '<span class="rl-price">' + fmt(l.price_unit) + '</span></div>';
        });
        html += '</div>';
        html += '<div class="pos-form-group"><label>เหตุผลการคืน</label><input type="text" id="returnReason" placeholder="เช่น สินค้าชำรุด, ลูกค้าเปลี่ยนใจ"/></div>';
        html += '<div class="pos-form-group"><label>วิธีการคืนเงิน</label><select id="returnPaymentMethod">'
            + '<option value="cash">💵 เงินสด (Cash)</option>'
            + '<option value="transfer">🏦 โอน (Transfer)</option>'
            + '<option value="card">💳 บัตรเครดิต (Card)</option>'
            + '<option value="promptpay">📱 พร้อมเพย์ (PromptPay)</option>'
            + '</select></div>';
        html += '<div class="pos-return-total-box"><span>ยอดคืนโดยประมาณ</span><span class="amount" id="returnTotalAmount">฿0.00</span></div>';
        document.getElementById('returnWizardBody').innerHTML = html;
        calcReturnTotal();
    } catch (e) { showToast('โหลดรายละเอียดออเดอร์ไม่สำเร็จ', 'error'); }
}

function onReturnCheckChange(idx) {
    const cb = document.getElementById('retCb' + idx);
    const qty = document.getElementById('retQty' + idx);
    if (cb && qty && cb.checked && (!qty.value || parseFloat(qty.value) <= 0)) {
        qty.value = qty.getAttribute('max');
    }
    calcReturnTotal();
}

function clampReturnQty(idx) {
    const qty = document.getElementById('retQty' + idx);
    if (!qty) return;
    const max = parseFloat(qty.getAttribute('max')) || 1;
    let v = Math.floor(parseFloat(qty.value) || 1);
    if (v < 1) v = 1;
    if (v > max) { v = max; showToast('จำนวนคืนได้สูงสุด ' + max, 'warning'); }
    qty.value = v;
    calcReturnTotal();
}

function calcReturnTotal() {
    let total = 0;
    document.querySelectorAll('.return-checkbox:checked').forEach(function (cb) {
        const idx = cb.id.replace('retCb', '');
        const price = parseFloat(cb.getAttribute('data-price')) || 0;
        const qtyEl = document.getElementById('retQty' + idx);
        const qty = qtyEl ? (parseFloat(qtyEl.value) || 0) : 0;
        total += price * qty;
    });
    const el = document.getElementById('returnTotalAmount');
    if (el) el.textContent = fmt(total);
}

async function confirmReturn() {
    if (state.returnSubmitting) return;
    const checked = document.querySelectorAll('.return-checkbox:checked');
    if (!checked.length) { showToast('กรุณาเลือกสินค้าที่ต้องการคืน', 'warning'); return; }

    const lines = [];
    let valid = true;
    checked.forEach(function (cb) {
        const idx = cb.id.replace('retCb', '');
        const qtyEl = document.getElementById('retQty' + idx);
        const qty = qtyEl ? Math.floor(parseFloat(qtyEl.value) || 0) : 0;
        const max = parseFloat(cb.getAttribute('data-max')) || 0;
        if (qty <= 0 || qty > max) { valid = false; return; }
        lines.push({
            product_id: parseInt(cb.getAttribute('data-product-id')),
            qty: qty,
            price_unit: parseFloat(cb.getAttribute('data-price')) || 0,
        });
    });
    if (!valid || !lines.length) { showToast('จำนวนคืนไม่ถูกต้อง', 'error'); return; }

    state.returnSubmitting = true;
    const btn = document.getElementById('confirmReturnBtn');
    btn.disabled = true;
    btn.innerHTML = '<span class="pos-spinner"></span>กำลังบันทึก...';

    try {
        const data = await jsonRpc('/pos_lite/api/create_return', {
            original_order_id: state.returnOrderId,
            lines: lines,
            reason: (document.getElementById('returnReason') || {}).value || '',
            payment_method: (document.getElementById('returnPaymentMethod') || {}).value || 'cash',
            session_id: CURRENT_SESSION_ID,
            employee_id: state.selectedEmployeeId,
        });
        if (data.success) {
            showToast('คืนสินค้าสำเร็จ — ' + data.name, 'success');
            closeReturnWizard();
            loadProducts(); // returned stock comes back
        } else {
            showToast('เกิดข้อผิดพลาด: ' + (data.error || 'ไม่ทราบสาเหตุ'), 'error');
        }
    } catch (e) {
        showToast('ไม่สามารถดำเนินการคืนสินค้าได้: ' + e.message, 'error');
    } finally {
        state.returnSubmitting = false;
        btn.disabled = false;
        btn.innerHTML = 'ยืนยันการคืนเงิน';
    }
}

function closeReturnWizard() {
    if (state.returnSubmitting) return;
    document.getElementById('posReturnWizardModal').classList.remove('open');
    state.returnOrderId = null;
}

// ─── Keyboard ──────────────────────────────────────────────
document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape') {
        closeProcessModal(); closeEmployeeSwitch(); closePrintDetail(); closeReturnWizard(); closeHistoryOrders();
        closeCatMenu(); closeCustResults();
    }
    if (e.key === 'F2') { e.preventDefault(); const s = document.getElementById('posSearch'); if (s) s.focus(); }
    if (e.key === 'F4' || e.key === 'F9') {
        e.preventDefault();
        const btn = document.getElementById('posPayBtn');
        if (btn && !btn.disabled && !document.getElementById('posProcessModal').classList.contains('open')) openProcessModal();
    }
});

// Close floating menus on outside click
document.addEventListener('click', function (e) {
    if (!e.target.closest('#posCatMenu') && !e.target.closest('#posCatMoreBtn')) closeCatMenu();
    if (!e.target.closest('.pos-cust-search')) closeCustResults();
});

// ─── Bootstrap ──────────────────────────────────────────────
